  ('elementary-814ced5a-moex-00650', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '小智今年12歲，他所從事的下列何項行為須經法定代理人同意才具有法律效力？', '["接受小華母親贈送的生日禮物", "用母親給的零用錢購買早餐", "和鄰居協議賠償打破鄰居玻璃的費用", "用自己存款繳交班級活動費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00651', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '對於死刑定讞之案件，其執行命令經法務部部長簽署後，依法應由下列何者執行？', '["受命法官", "檢察官", "檢察總長", "檢察長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00652', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '阿強涉嫌綁架撕票案，被法院判處死刑定讞，但辯護律師認為證據不足、法官拒絕被告到庭詰問，且經 專家鑑定發現有新事證足以推翻原判決。該案依相關法律判斷，下列敘述何者正確？', '["律師可向最高法院提出非常上訴", "阿強可委託律師向最高法院聲請再審", "最高檢察署可向最高法院聲請更審", "死刑執行檢察官可向最高法院提出非常上訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00653', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '有些人認為對犯罪者要處以刑罰，是讓民眾知道犯罪的下場，警惕自己不要犯罪。此種思維是屬於下列 何種刑罰理論？', '["應報理論", "一般預防理論", "特別預防理論", "綜合理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00654', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '根據我國憲法增修條文及相關法律規定，甲就其職權相關之國家大政方針，得向乙進行國情報告。關於 甲、乙的職權及其運作，下列敘述何者正確？', '["甲係由乙直接任命之", "甲可對乙提出覆議案", "乙可對甲提出彈劾案", "乙可對甲提出倒閣案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00655', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '2015年8月我國甲與中國乙本於平等互惠原則，共同簽署海峽兩岸避免雙重課稅及加強稅務合作協議。 上述代表雙方簽署協議的機構甲與乙分別為下列何者？', '["甲為財團法人海峽交流基金會、乙為海峽兩岸關係協會", "甲為海峽兩岸關係協會、乙為財團法人海峽交流基金會", "甲為大陸委員會、乙為海峽兩岸關係協會", "甲為大陸委員會、乙為國務院臺灣事務辦公室"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00656', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '國人A自中國大陸返臺就醫，引起各界輿論關注。行政院院長赴立法院備詢前受訪表示，是否應限縮健 保使用資格，他在擔任政務委員時，就曾提出限縮在大陸的臺胞與旅居國外僑胞的健保資格。行政院院 長前述表示係屬於政府決策過程的那一階段？', '["政策規劃", "政策合法化", "政策執行", "政策評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
